/**
 * @param   cluster   cluster number starts from 2, which means no 0 and 1
 */
static inline uint32 first_sec_of_clus(struct fs * self_fs, uint32 cluster)
{
    return ((cluster - 2) * self_fs->fat.bpb.sec_per_clus) + self_fs->fat.first_data_sec;
}

/**
 * For the given number of a data cluster, return the number of the sector in a FAT table.
 * @param   cluster     number of a data cluster
 * @param   fat_num     number of FAT table from 1, shouldn't be larger than bpb::fat_cnt
 */
static inline uint32 fat_sec_of_clus(struct fs * self_fs, uint32 cluster, uint8 fat_num)
{
    return self_fs->fat.bpb.rsvd_sec_cnt + (cluster << 2) / self_fs->fat.bpb.byts_per_sec + self_fs->fat.bpb.fat_sz * (fat_num - 1);
}

/**
 * For the given number of a data cluster, return the offest in the corresponding sector in a FAT table.
 * @param   cluster   number of a data cluster
 */
static inline uint32 fat_offset_of_clus(struct fs * self_fs, uint32 cluster)
{
    return (cluster << 2) % self_fs->fat.bpb.byts_per_sec;
}

/**
 * Read the FAT table content corresponded to the given cluster number.
 * @param   cluster     the number of cluster which you want to read its content in FAT table
 */
static uint32 read_fat(struct fs * self_fs, uint32 cluster)
{
    if (cluster >= FAT32_EOC) {
        return cluster;
    }
    if (cluster > self_fs->fat.data_clus_cnt + 1) {     // because cluster number starts at 2, not 0
        return 0;
    }
    uint32 fat_sec = fat_sec_of_clus(self_fs, cluster, 1);
    // here should be a cache layer for FAT table, but not implemented yet.
    struct buf *b = bread(self_fs->devno, fat_sec);
    uint32 next_clus = *(uint32 *)(b->data + fat_offset_of_clus(self_fs, cluster));
    brelse(b);
    return next_clus;
}

/**
 * Write the FAT region content corresponded to the given cluster number.
 * @param   cluster     the number of cluster to write its content in FAT table
 * @param   content     the content which should be the next cluster number of FAT end of chain flag
 */
static int write_fat(struct fs * self_fs, uint32 cluster, uint32 content)
{
    if (cluster > self_fs->fat.data_clus_cnt + 1) {
        return -1;
    }
    uint32 fat_sec = fat_sec_of_clus(self_fs, cluster, 1);
    struct buf *b = bread(self_fs->devno, fat_sec);
    uint off = fat_offset_of_clus(self_fs, cluster);
    *(uint32 *)(b->data + off) = content;
    bwrite(self_fs->devno, b);
    brelse(b);
    return 0;
}

