  if (p->unmapped_idx >= 0 && p->unmapped_idx < MMAPNUM) {
    i = p->unmapped_idx;
    p->unmapped_idx++;
    return i;
  }

  // for(i = 0; i < MMAPNUM; i++)
  // {
