```

#### 关键功能实现

**1. 进程创建 (fork)**
```c
// kernel/proc.c: fork()
int fork(void) {
  struct proc *np = allocproc();
  if(!np) return -1;

  // 复制用户内存（完整拷贝）
  uvmcopy(p->pagetable, np->pagetable, np->kpagetable, p->sz);
  np->sz = p->sz;
  np->parent = p;
  np->tmask = p->tmask;  // 继承追踪掩码

  // 复制trapframe（除a0外）
  *np->trapframe = *p->trapframe;
  np->trapframe->a0 = 0;  // 子进程fork返回0

  // 复制打开文件和cwd
  for(int i = 0; i < NOFILE; i++)
    if(p->ofile[i]) np->ofile[i] = filedup(p->ofile[i]);
  np->cwd = edup(p->cwd);

  np->state = RUNNABLE;
  return np->pid;
}
```

**2. 进程克隆 (clone)**
```c
// kernel/proc.c: clone()
int clone(uint64 flag, uint64 stack) {
  struct proc *np = allocproc();
  // 与fork类似，但使用用户提供的栈地址
  np->trapframe->sp = stack;
  // 共享内存空间（未实现COW）
  uvmcopy(p->pagetable, np->pagetable, np->kpagetable, p->sz);
  return np->pid;
}
```

**3. 进程调度**
```c
// kernel/proc.c: scheduler()
void scheduler(void) {
  struct cpu *c = mycpu();
  for(;;) {
    intr_on();  // 允许中断
    for(struct proc *p = proc; p < &proc[NPROC]; p++) {
      acquire(&p->lock);
      if(p->state == RUNNABLE) {
        p->state = RUNNING;
        c->proc = p;
        swtch(&c->context, &p->context);  // 上下文切换
        c->proc = 0;
      }
      release(&p->lock);
    }
  }
}
```

**4. 上下文切换**
```assembly
# kernel/swtch.S
swtch:
  # 保存callee-saved寄存器到old context
  sd ra, 0(a0)
  sd sp, 8(a0)
  sd s0-s11, 16-104(a0)

  # 从new context恢复寄存器
  ld ra, 0(a1)
  ld sp, 8(a1)
  ld s0-s11, 16-104(a1)
  ret
```

