int consoleread(int user_dst, uint64 dst, int n) {
  while(n > 0) {
    while(cons.r == cons.w) {
      sleep(&cons.r, &cons.lock);
    }
    char c = cons.buf[cons.r++ % INPUT_BUF];
    if(c == C('D')) break;  // EOF
    either_copyout(user_dst, dst, &c, 1);
    if(c == '\n') break;
  }
  return target - n;
}
