#### 管道
```c
// kernel/pipe.c
int pipewrite(struct pipe *pi, uint64 addr, int n) {
  acquire(&pi->lock);
  for(int i = 0; i < n; i++) {
    while(pi->nwrite == pi->nread + PIPESIZE) {
      if(pi->readopen == 0 || myproc()->killed) {
        release(&pi->lock);
        return -1;
      }
      wakeup(&pi->nread);
      sleep(&pi->nwrite, &pi->lock);
    }
    char ch;
    copyin2(&ch, addr + i, 1);
    pi->data[pi->nwrite++ % PIPESIZE] = ch;
  }
  wakeup(&pi->nread);
  release(&pi->lock);
  return n;
}
