# kernel/entry_vf2.S
.section .text
.globl _entry
_entry:
  add t0, a0, 1        # hartid + 1
  slli t0, t0, 14      # * 16KB（每核栈大小）
  la sp, boot_stack
  add sp, sp, t0       # 设置栈指针
  call main

.section .bss.stack
.align 12
.globl boot_stack
boot_stack:
  .space 4096 * 4 * 4  # 64KB栈空间（4核）
