#### 内核主函数
```c
// kernel/main.c
void main(unsigned long hartid, unsigned long dtb_pa) {
  sbi_console = 1;
  inithartid(hartid);

  if(boothartid == -1) {
    boothartid = hartid;

    consoleinit();
    printfinit();
    print_logo();

    kinit();         // 物理内存
    kvminit();       // 内核页表
    kvminithart();   // 启用分页
    timerinit();     // 定时器
    trapinithart();  // 陷阱向量
    uart_init();     // UART
    procinit();      // 进程表
    plicinit();      // PLIC
    plicinithart(hartid);
    binit();         // 缓冲区
    fileinit();      // 文件表
    userinit();      // 初始进程

    started = 1;
  } else {
    while(started == 0);
    kvminithart();
    trapinithart();
    plicinithart(hartid);
  }

  scheduler();  // 进入调度循环
}
```

